const express = require('express');
const axios = require('axios');
const { v4: uuidv4 } = require('uuid');

const app = express();
app.use(express.json());

// Set up LLM API endpoint
const llmApiUrl = 'https://api.llama.tech/v1/completions';
const apiKey = 'YOUR_API_KEY_HERE';

// Function to generate code from prompt
async function generateCode(prompt) {
  try {
    const response = await axios.post(llmApiUrl, {
      model: 'code-davinci-002',
      prompt,
      max_tokens: 2048,
      temperature: 0.7,
      top_p: 1,
      n: 1,
      stream: false
    }, {
      headers: {
        'Authorization': `Bearer ${apiKey}`,
        'Content-Type': 'application/json'
      }
    });

    const code = response.data.choices[0].text;
    return code;
  } catch (error) {
    console.error(error);
    throw error;
  }
}

// API endpoint to generate code
app.post('/generate-code', async (req, res) => {
  try {
    const prompt = req.body.prompt;

    if (!prompt) {
      return res.status(400).json({ error: 'Prompt is required' });
    }

    const code = await generateCode(prompt);
    res.json({ code });
  } catch (error) {
    console.error(error);
    res.status(500).json({ error: 'Failed to generate code' });
  }
});

// API endpoint to execute generated code
app.post('/execute-code', async (req, res) => {
  try {
    const code = req.body.code;

    if (!code) {
      return res.status(400).json({ error: 'Code is required' });
    }

    // Execute the code here using a suitable library or framework
    // For example, you can use child_process to execute shell commands
    const exec = require('child_process').exec;
    exec(code, (error, stdout, stderr) => {
      if (error) {
        console.error(error);
        res.status(500).json({ error: 'Failed to execute code' });
      } else {
        res.json({ output: stdout });
      }
    });
  } catch (error) {
    console.error(error);
    res.status(500).json({ error: 'Failed to execute code' });
  }
});

const port = process.env.PORT || 3000;
app.listen(port, () => {
  console.log(`Server listening on port ${port}`);
});